#[derive(Clone, Copy, Debug, Default)]
pub enum Direction {
    #[default]
    Ltr,
    Rtl,
    Auto,  // Inherit from locale
}

// Extension to FlexLayout
impl FlexLayout {
    pub fn direction(self, dir: Direction) -> Self;
    pub fn mirror_in_rtl(self, mirror: bool) -> Self;
}

// Extension to Style
impl Style {
    /// Swap start/end padding in RTL
    pub fn logical_padding(self, start: u16, end: u16) -> Self;

    /// Swap left/right margin in RTL  
    pub fn logical_margin(self, start: u16, end: u16) -> Self;

    /// Text alignment aware of direction
    pub fn logical_align(self, align: LogicalAlign) -> Self;
}

#[derive(Clone, Copy)]
pub enum LogicalAlign {
    Start,  // Left in LTR, Right in RTL
    End,    // Right in LTR, Left in RTL
    Center,
}

// LTR override for specific content
pub fn ltr_isolate<W: Widget>(widget: W) -> LtrIsolate<W>;
```

