```rust
// In flex solver
fn resolve_direction(&self, locale: &Locale) -> PhysicalDirection {
    match self.direction {
        Direction::Ltr => PhysicalDirection::LeftToRight,
        Direction::Rtl => PhysicalDirection::RightToLeft,
        Direction::Auto => if locale.is_rtl() { 
            PhysicalDirection::RightToLeft 
        } else { 
            PhysicalDirection::LeftToRight 
        },
    }
}

// Reverse child order for RTL flex rows
fn layout_children(&mut self) {
    let children = if self.is_rtl() && self.main_axis == Axis::Horizontal {
        self.children.iter().rev()
    } else {
        self.children.iter()
    };
    // ... layout logic
}
```

