+#[test]
+fn inline_reflow_ghost1_shrink_clears_stale_rows() {
+    log_jsonl("start", &[("test", "ghost1_shrink")]);
+    let mut output = Vec::new();
+    {
+        let mut w = TerminalWriter::new(
+            &mut output,
